    setbuf(stdout, NULL);
    int fd[2];
    pipe(fd);
    pid_t pid = fork();
    if (pid == 0) {
        close(fd[1]);
        char buf[64];
        ssize_t n = read(fd[0], buf, sizeof(buf) - 1);
        buf[n] = '\0';
        printf("Enfant recu: %s\n", buf);
        close(fd[0]);
        _exit(0);
    } else {
        close(fd[0]);
        const char *msg = "Bonjour fils";
        write(fd[1], msg, strlen(msg));
        close(fd[1]);
        wait(NULL);
    }
    return 0;
}

